import{b as e,I as i,g as a,j as t}from"./chunks/framework.DUo3J_Qe.js";const c=JSON.parse('{"title":"Introduction à Seaborn","description":"","frontmatter":{},"headers":[],"relativePath":"fr/learning/libraries/seaborn/introduction.md","filePath":"fr/learning/libraries/seaborn/introduction.md"}'),l={name:"fr/learning/libraries/seaborn/introduction.md"};function n(r,s,o,p,d,u){return i(),a("div",null,[...s[0]||(s[0]=[t(`<h1 id="introduction-a-seaborn" tabindex="-1">Introduction à <a href="https://seaborn.pydata.org/" target="_blank" rel="noreferrer">Seaborn</a> <a class="header-anchor" href="#introduction-a-seaborn" aria-label="Permalink to &quot;Introduction à [Seaborn](https://seaborn.pydata.org/)&quot;">​</a></h1><p><code>Seaborn</code>, une bibliothèque Python construite au-dessus de Matplotlib dédiée à la <strong>visualisation statistique des données</strong>, est conçue pour fonctionner <strong>nativement avec les DataFrames Pandas</strong> et permet de produire rapidement des graphiques statistiques clairs, esthétiques et informatifs.</p><p>Elle a pour objectif de :</p><ul><li>simplifier la création de graphiques statistiques</li><li>réduire la quantité de code nécessaire</li><li>fournir des visualisations par défaut esthétiques et cohérentes</li></ul><blockquote><p>📌 Seaborn est particulièrement adaptée à l’<strong>exploration de données (EDA)</strong>.</p></blockquote><h2 id="seaborn-pandas" tabindex="-1">Seaborn &amp; Pandas <a class="header-anchor" href="#seaborn-pandas" aria-label="Permalink to &quot;Seaborn &amp; Pandas&quot;">​</a></h2><p>Seaborn est pensée pour interagir directement avec les <strong>DataFrames Pandas</strong>.</p><ul><li>Les données sont passées via l’argument data</li><li>Les variables sont référencées par leurs noms de colonnes</li><li>Les graphiques sont automatiquement adaptés aux types de données</li></ul><div class="info custom-block"><p class="custom-block-title">➡️</p><p>Contrairement à Matplotlib, on ne manipule pas directement les tableaux NumPy dans la majorité des cas.</p></div><h2 id="philosophie-de-seaborn" tabindex="-1">Philosophie de Seaborn <a class="header-anchor" href="#philosophie-de-seaborn" aria-label="Permalink to &quot;Philosophie de Seaborn&quot;">​</a></h2><h3 id="une-syntaxe-simple-et-expressive" tabindex="-1">Une syntaxe simple et expressive <a class="header-anchor" href="#une-syntaxe-simple-et-expressive" aria-label="Permalink to &quot;Une syntaxe simple et expressive&quot;">​</a></h3><p>La majorité des graphiques Seaborn peuvent être créés en <em><strong>une seule ligne de code</strong></em>.</p><div class="tip custom-block"><p class="custom-block-title">Exemple : nuage de points (scatter plot)</p><div class="language-py vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">py</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> seaborn </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">as</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> sns</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">sns.scatterplot(</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">x</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;age&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">y</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;salary&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">data</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">df)</span></span></code></pre></div><ul><li><code>x</code> et <code>y</code> sont des chaînes de caractères</li><li>Elles correspondent aux colonnes du DataFrame</li><li><code>data</code> contient la source des données</li></ul><p>➡️ Le graphique est généré automatiquement, sans configuration supplémentaire.</p></div><h3 id="une-abstraction-au-dessus-de-matplotlib" tabindex="-1">Une abstraction au-dessus de Matplotlib <a class="header-anchor" href="#une-abstraction-au-dessus-de-matplotlib" aria-label="Permalink to &quot;Une abstraction au-dessus de Matplotlib&quot;">​</a></h3><p>Seaborn utilise exactement les mêmes objets que Matplotlib : <code>Figure</code> &amp; <code>Axes</code>. Cela signifie que :</p><ul><li>Seaborn crée le graphique</li><li>Matplotlib peut ensuite être utilisé pour le personnaliser</li></ul><div class="tip custom-block"><p class="custom-block-title">Exemple</p><div class="language-py vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">py</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> matplotlib.pyplot </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">as</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> plt</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">sns.scatterplot(</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">x</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;age&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">y</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;salary&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">data</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">df)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">plt.title(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Salaire en fonction de l&#39;âge&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">plt.xlabel(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Âge&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">plt.ylabel(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Salaire&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><p>➡️ Seaborn = simplicité ➡️ Matplotlib = personnalisation fine</p></div><blockquote><p>Les deux bibliothèques sont <strong>complémentaires</strong>, pas concurrentes.</p></blockquote><h2 id="types-de-graphiques-disponibles" tabindex="-1">Types de graphiques disponibles <a class="header-anchor" href="#types-de-graphiques-disponibles" aria-label="Permalink to &quot;Types de graphiques disponibles&quot;">​</a></h2><ul><li>Diagrammes de dispersion</li><li>Diagrammes de distribution</li><li>Diagrammes catégoriels</li><li>Diagrammes de comparaison</li><li>Grilles Seaborn (Grids)</li><li>Diagrammes matriciels</li></ul><div class="info custom-block"><p class="custom-block-title">quand et pourquoi utiliser chaque type de graphique ?</p><p>La réponse dépend :</p><ul><li>du type de variables (numérique, catégorielle)</li><li>de la relation que vous cherchez à analyser</li><li>de la question que vous vous posez</li></ul></div><div class="warning custom-block"><p class="custom-block-title">Important :</p><p>👉 Toutes les questions ne nécessitent pas un graphique. Parfois, une simple statistique descriptive suffit.</p></div><h2 id="variables-continues-vs-variables-categorielles" tabindex="-1">Variables continues vs variables catégorielles <a class="header-anchor" href="#variables-continues-vs-variables-categorielles" aria-label="Permalink to &quot;Variables continues vs variables catégorielles&quot;">​</a></h2><h3 id="variables-continues" tabindex="-1">Variables continues <a class="header-anchor" href="#variables-continues" aria-label="Permalink to &quot;Variables continues&quot;">​</a></h3><p>Une <strong>variable continue</strong> est une variable numérique qui peut prendre une <strong>infinité de valeurs possibles</strong> dans un intervalle (âge, taille, salaire, température, prix, distance etc.)</p><div class="tip custom-block"><p class="custom-block-title">Exemple</p><p>Un âge de 28 ans peut être affiné :</p><ul><li>28 ans</li><li>28 ans et 2 mois</li><li>28 ans, 2 mois et 1 semaine</li></ul><p>➡️ On peut toujours diviser l’unité de mesure.</p></div><h3 id="variables-categorielles" tabindex="-1">Variables catégorielles <a class="header-anchor" href="#variables-categorielles" aria-label="Permalink to &quot;Variables catégorielles&quot;">​</a></h3><p>Une <strong>variable catégorielle</strong> représente des catégories <strong>distinctes et non continues</strong>.</p><div class="tip custom-block"><p class="custom-block-title">Exemple</p><ul><li>niveau d’éducation (lycée, bachelor, master)</li><li>couleur (rouge, vert, bleu)</li><li>forme (carré, triangle, cercle)</li><li>noms (Marc, Claire, Vincent)</li></ul><p>➡️ Il n’existe pas de valeur intermédiaire entre deux catégories.</p></div>`,29)])])}const k=e(l,[["render",n]]);export{c as __pageData,k as default};
